output.sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX pq: <http://www.wikidata.org/prop/qualifier/>
PREFIX ps: <http://www.wikidata.org/prop/statement/>
PREFIX p: <http://www.wikidata.org/prop/>
SELECT ?horse ?horseLabel ?jockey ?jockeyLabel WHERE {
  wd:Q4600256 p:P710 ?participant ; pq:P1352 "1" ; pq:P5317 ?jockey ; ps:P710 ?horse ;
  OPTIONAL {
    ?horse rdfs:label ?horseLabel .
    FILTER(LANG(?horseLabel) = 'en')
  }
  OPTIONAL {
    ?jockey rdfs:label ?jockeyLabel .
    FILTER(LANG(?jockeyLabel) = 'en')
  }
}

